<template><view class="page"><xy-header title="我的会员卡"/><view class="wrap"><view v-if="card" class="member-card"><text>{{card.planName}}</text><text class="no">{{card.cardNo}}</text><text>有效期：{{card.startDate}} 至 {{card.expireDate}}</text><text>已预约 {{card.usageCount}} 次</text></view><view v-else class="empty">暂无有效会员卡<button @click="join">立即开通</button></view><button v-if="card" @click="code">出示会员码</button><button @click="profile">会员资料</button></view></view></template>
<script>import{appRequest,ensureMemberSession,showRequestError}from'../../utils/api';export default{data(){return{card:null}},onShow(){this.load()},methods:{async load(){try{await ensureMemberSession();const me=await appRequest({url:'/app/me'});this.card=me.card}catch(e){showRequestError(e)}},join(){uni.navigateTo({url:'/pages/membership/join'})},code(){uni.navigateTo({url:'/pages/membership/code'})},profile(){uni.navigateTo({url:'/pages/membership/profile'})}}}</script>
<style scoped>.page{min-height:100vh;background:var(--xy-bg)}.wrap{padding:28rpx}.member-card{display:flex;flex-direction:column;gap:22rpx;padding:42rpx;border-radius:28rpx;background:linear-gradient(135deg,#173e3b,#0e9c8e);color:#fff}.member-card>text:first-child{font-size:36rpx;font-weight:700}.no{font-size:28rpx;letter-spacing:3rpx}.empty{text-align:center;padding:100rpx;color:var(--xy-muted)}button{margin-top:24rpx}</style>
